        Assert.Equal (2, optionSelector.Value); // Value should remain unchanged

        Assert.True (tabBehavior == TabBehavior.NoStop ? checkBoxes [1].HasFocus : checkBoxes [2].HasFocus);

        optionSelector.Dispose ();
