    [Fact]
    public void Values_NonSequential_ShouldWorkCorrectly ()
    {
        // Arrange
        OptionSelector optionSelector = new ();
        List<string> options = ["Option _1", "Option _2", "Option _3"];
        List<int> values = [0, 1, 5];

        optionSelector.Labels = options;
